public class KnapsackMemoization {

    // DP array for memoization, -1 means not computed
    private static int[][] memo;

    public static int knapsack(int[] values, int[] weights, int n, int W) {
        memo = new int[n + 1][W + 1];

        // Initialize with -1 (uncomputed)
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= W; j++) {
                memo[i][j] = -1;
            }
        }

        return solve(values, weights, n, W);
    }

    private static int solve(int[] values, int[] weights, int i, int w) {
        // Base case: no items or no capacity
        if (i == 0 || w == 0) {
            return 0;
        }

        // Return cached result if already computed
        if (memo[i][w] != -1) {
            return memo[i][w];
        }

        // If weight of current item is more than capacity, skip it
        if (weights[i - 1] > w) {
            memo[i][w] = solve(values, weights, i - 1, w);
        } else {
            // Maximum of including or excluding current item
            int include = values[i - 1] + 
                solve(values, weights, i - 1, w - weights[i - 1]);
            int exclude = solve(values, weights, i - 1, w);
            memo[i][w] = Math.max(include, exclude);
        }

        return memo[i][w];
    }

    public static void main(String[] args) {
        int[] values = {10, 10, 12, 18};
        int[] weights = {2, 3, 4, 5};
        int W = 8;
        int n = values.length;

        System.out.println("Maximum value: " + knapsack(values, weights, n, W));
    }
}
